@Component({
  selector: 'app-split-rail',
  templateUrl: './split-rail.component.html',
  styleUrls: ['./split-rail.component.scss'],
  standalone: false
})
export class SplitRailComponent {
  private _item: any = null;

  @Input() set item(val: any) {
    this._item = val;
    this.buildFields();
  }

  @Input() imgSrc: string | null = null;

  fields: Array<{ label: string; value: string; mono?: boolean; full?: boolean }> = [];
  statusLabel = '';
  statusTone = { bg: '#f1eee9', fg: '#46454f', dot: '#76747f' };

  constructor(private router: Router) {}

  private buildFields(): void {
    if (!this._item) {
      this.fields = [];
      this.statusLabel = '';
      this.statusTone = STATUS_TONES['concept'];
      return;
    }

    this.statusLabel = this._item.status || '';
    const key = STATUS_KEY_MAP[this.statusLabel.toLowerCase().trim()] || 'concept';
    this.statusTone = STATUS_TONES[key];

    this.fields = [
      { label: 'Item Num',     value: this._item.itemNum || '—',                                              mono: true  },
      { label: 'Reference #',  value: this._item.refNum || '—',                                               mono: true  },
      { label: 'Design #',     value: this._item.DSN || '—',                                                  mono: true  },
      { label: 'Season',       value: this._item.season || '—',                                               mono: true  },
      { label: 'Licensor',     value: this._item.licensorName || this._item.licensor || '—',                  full: true  },
      { label: 'Product Type', value: this._item.materialName  || this._item.material  || '—'                            },
      { label: 'Sub-Type',     value: this._item.constructionName || this._item.construction || '—'                       },
      { label: 'Feature',      value: this._item.featureName   || this._item.feature   || '—'                            },
      { label: 'Size',         value: this._item.sizeName      || this._item.size      || '—',                mono: true  },
      { label: 'Division',     value: String(this._item.div_code_fk || '—')                                              }
    ];
  }

  onOpen(): void {
    if (this._item?.id) {
      this.router.navigate(['/apps/itemDetail/' + this._item.id]);
    }
  }

  get itemName(): string {
    return this._item?.item_name || this._item?.name || '';
  }

  get itemMeta(): string {
    return [this._item?.propertyName || this._item?.property, this._item?.materialName || this._item?.material]
      .filter(Boolean)
      .join(' · ');
  }

  get hasItem(): boolean {
    return !!this._item;
  }
}

