@Component({
  selector: 'app-item-gallery',
  templateUrl: './gallery.component.html',
  styleUrls: ['./gallery.component.scss'],
  standalone: false
})
export class GalleryComponent {
  @Input() items: any[] = [];
  @Input() selectedIds: Set<any> = new Set();
  @Input() density: 'comfortable' | 'compact' = 'comfortable';

  @Output() selectionChange = new EventEmitter<{ item: any; checked: boolean }>();
  @Output() itemOpen = new EventEmitter<any>();

  isSelected(item: any): boolean {
    return this.selectedIds.has(item.id);
  }

  onCheck(item: any, checked: boolean): void {
    this.selectionChange.emit({ item, checked });
  }

  onDblClick(item: any): void {
    this.itemOpen.emit(item);
  }

  getStatusTone(status: string): { bg: string; fg: string; dot: string } {
    const key = STATUS_KEY_MAP[(status || '').toLowerCase().trim()] || 'concept';
    return STATUS_TONES[key];
  }

  getPropertyDot(item: any): string {
    const hue = stringToHue(String(item.property || item.property_id || ''));
    return `hsl(${hue} 45% 52%)`;
  }

  getTileGradient(item: any): string {
    const h = stringToHue(String(item.property || item.property_id || ''));
    return `linear-gradient(150deg, hsl(${h} 46% 95%), hsl(${h} 40% 87%))`;
  }

  getTileBorder(item: any): string {
    const h = stringToHue(String(item.property || item.property_id || ''));
    return `1px solid hsl(${h} 30% 80%)`;
  }

  getThumbSrc(item: any): string | null {
    return item?.pic?.Thumbnail || item?.pic?.FullSizePicture || null;
  }
}

